function makePlayer(name) {
  return { id: crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).slice(2), name, ready: name !== "Patryk", alive: true, role: null, faction: null, roleRevealed: false, roleAcknowledged: false, nightSubmitted: false, voteSubmitted: false, immunityActive:false, vestActive:false, doubleVoteArmed:false, teflonActive:false, ricochetArmed:false, silencedUntilDayEnd:false, intimidatedUntilNightEnd:false, cards: [] };
}
function clearAllTimers(){state.timers.forEach(clearTimeout);state.timers=[]}
function later(fn,ms){const id=setTimeout(fn,ms);state.timers.push(id);return id}
function shuffle(arr){const copy=[...arr];for(let i=copy.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[copy[i],copy[j]]=[copy[j],copy[i]]}return copy}
function formatSeconds(total){const clamped=Math.max(0,total);const minutes=Math.floor(clamped/60);const seconds=clamped%60;return `${minutes}:${String(seconds).padStart(2,"0")}`}
function secondsLeftFromEnd(endAt){if(!endAt)return 0;return Math.max(0,Math.ceil((endAt-Date.now())/1000))}
function selectedPlayer(){return state.players.find(p=>p.id===state.selectedPlayerId)||state.players[0]||null}
function mafiaActorIds(){return state.players.filter(p=>p.role==="mafia").map(p=>p.id)}
function alivePlayers(players=state.players){return players.filter(p=>p.alive)}
function aliveMafiaActorIds(players=state.players){return alivePlayers(players).filter(p=>p.role==="mafia").map(p=>p.id)}
function targetGenderText(name,male,female){return name.trim().toLowerCase().endsWith("a")?female:male}
function getRoleTeamText(player,players){if(!player||!player.role||player.role!=="mafia"){return player&&player.role?ROLE_META[player.role].revealText:""}const teammates=players.filter(p=>p.id!==player.id&&p.role==="mafia").map(p=>p.name).join(", ");return teammates?`${teammates} gra z Tobą, wyeliminujcie resztę!`:ROLE_META.mafia.revealText}
function countTargetsFromActors(targetMap, allowedActors){return Object.entries(targetMap).reduce((acc,[actorId,targetId])=>{if(!allowedActors.includes(actorId))return acc;acc[targetId]=(acc[targetId]||0)+1;return acc},{})}
function getConsensusTargetId(targetMap, actorIds){const ranked=Object.entries(countTargetsFromActors(targetMap, actorIds)).sort((a,b)=>b[1]-a[1]);if(!ranked.length)return null;if(ranked.length>1&&ranked[0][1]===ranked[1][1])return null;return ranked[0][0]}
function getWinner(players){const alive=players.filter(p=>p.alive);const mafiaAlive=alive.filter(p=>p.faction==="Mafia").length;const townAlive=alive.filter(p=>p.faction==="Miasto").length;if(mafiaAlive===0)return "Miasto";if(mafiaAlive>=townAlive)return "Mafia";return null}
function generateRoles(players, settings){const total=players.length;const roles=[];const mafiaCount=Math.min(settings.mafiaCount,Math.max(1,total-2));for(let i=0;i<mafiaCount;i++)roles.push("mafia");if(settings.enableDoctor&&roles.length<total)roles.push("doctor");if(settings.enableDetective&&roles.length<total)roles.push("detective");while(roles.length<total)roles.push("citizen");return shuffle(roles)}
function pulseFade(next){const fade=document.getElementById("fade");fade.classList.add("show");later(()=>{if(next)next();later(()=>fade.classList.remove("show"),220)},300)}
function chooseAndFlashPlayer(playerId,setter,afterSet){setter(playerId);if(afterSet)afterSet(playerId);state.activeFlashPlayerId=playerId;render();later(()=>{if(state.activeFlashPlayerId===playerId){state.activeFlashPlayerId=null;render()}},1000)}
function buildPerPlayerOrder(){const next={};state.players.forEach((viewer,viewerIdx)=>{const shuffled=shuffle([...state.players]);next[viewer.id]=shuffled.map((_,idx,arr)=>arr[(idx+viewerIdx)%arr.length])});return next}
function resetReady(){state.players=state.players.map(p=>({...p,ready:false}));render()}
function scopeLabel(scope){if(scope==="mafia")return "MAFIA";if(scope==="town")return "OBYWATEL";return "WSZYSCY"}
function timingLabel(timing){if(timing==="day")return "OBRADY";if(timing==="night")return "NOC";return "DOWOLNA FAZA"}
function isCardPhaseAllowed(card, phase){if(!card)return false;const timing=card.timing||"any";if(timing==="any")return ["day","night"].includes(phase);return phase===timing}
function canUseCard(card, player){if(!card||!player||card.used)return false;const meta=card.meta||SPECIAL_CARDS.find(c=>c.key===card.key);if(!meta)return false;if(meta.scope==="mafia"&&player.faction!=="Mafia")return false;if(meta.scope==="town"&&player.faction!=="Miasto")return false;return isCardPhaseAllowed(meta,state.phase)}
function cardUseError(card, player){if(!card||!player)return "Nie możesz teraz zagrać tej karty.";const meta=card.meta||SPECIAL_CARDS.find(c=>c.key===card.key);if(!meta)return "Brak definicji tej karty.";if(card.used)return "Ta karta została już użyta.";if(meta.scope==="mafia"&&player.faction!=="Mafia")return "Ta karta jest tylko dla frakcji MAFIA.";if(meta.scope==="town"&&player.faction!=="Miasto")return "Ta karta jest tylko dla frakcji OBYWATEL.";if(!isCardPhaseAllowed(meta,state.phase))return `Ta karta działa tylko w fazie: ${timingLabel(meta.timing)}.`;return ""}
function activeCardPool(){if(!state.settings.enableCards) return []; return SPECIAL_CARDS.filter(c=>state.settings.enabledCards[c.key])}
function createCardInstance(key, source){const meta=SPECIAL_CARDS.find(c=>c.key===key); return { instanceId:(crypto.randomUUID?crypto.randomUUID():Math.random().toString(36).slice(2)), key, source, used:false, delivered:false, seen:false, meta }}
function giveCardToPlayer(playerId, key, source){const player=state.players.find(p=>p.id===playerId); if(!player) return null; const instance=createCardInstance(key, source); player.cards.push(instance); return instance}
function dealStartCards(){const pool=activeCardPool(); if(!pool.length||!state.settings.enableCards||state.settings.startCardsCount<=0) return; const count=Math.min(state.settings.startCardsCount, state.players.length,  pool.length*10); const receivers=shuffle([...state.players]).slice(0, Math.min(count,state.players.length)); const queue=[]; receivers.forEach((player, idx)=>{const cardMeta=pool[Math.floor(Math.random()*pool.length)]; const instance=giveCardToPlayer(player.id, cardMeta.key, "start"); queue.push({playerId:player.id, cardInstanceId:instance.instanceId, type:"received"});}); state.players.forEach(player=>{if(!receivers.some(r=>r.id===player.id)){queue.push({playerId:player.id, type:"none"});}}); state.startCardQueue=queue;}
function getPlayerCardById(player, instanceId){return player.cards.find(c=>c.instanceId===instanceId)}
function hiddenCardHTML(){return `<div class="card-shell card-back centered"><div class="card-back-question">?</div></div>`}
function cardFaceHTML(card){const meta=card.meta||SPECIAL_CARDS.find(c=>c.key===card.key); return `<div class="card-shell"><div class="card-face"><div><div class="card-face-top">Karta specjalna</div><div class="card-face-name">${meta.name}</div></div><div class="card-face-desc">${meta.description}</div><div class="card-face-bottom"><div class="card-face-scope">${scopeLabel(meta.scope)}</div><div class="card-face-timing">${timingLabel(meta.timing)}</div></div></div></div>`}
function ensureAckFlow(key){if(!state.ackFlows[key]){state.ackFlows[key]={}}state.currentAckKey=key;return state.ackFlows[key]}
function clearAckFlow(key){delete state.ackFlows[key];if(state.currentAckKey===key){state.currentAckKey=""}}
function ackCountTextByKey(key, aliveOnly=false){const ackMap=state.ackFlows[key]||{};const pool=aliveOnly?state.players.filter(p=>p.alive):state.players;const total=pool.length;const done=pool.filter(p=>ackMap[p.id]).length;return `${done}/${total}`}
function isAckedInFlow(key, playerId){const ackMap=state.ackFlows[key]||{};return !!ackMap[playerId]}
function acknowledgeFlow(key,onEveryoneDone,aliveOnly=false){const sp=selectedPlayer();if(!sp)return;const ackMap=ensureAckFlow(key);const pool=aliveOnly?state.players.filter(p=>p.alive):state.players;if(!pool.some(p=>p.id===sp.id))return;if(ackMap[sp.id]) return;ackMap[sp.id]=true;render();const everyoneDone=pool.every(p=>ackMap[p.id]);if(everyoneDone){clearAckFlow(key);onEveryoneDone()}}
function bindPress(element, handler){if(!element)return;let pointerHandled=false;element.addEventListener("pointerup",(e)=>{e.preventDefault();pointerHandled=true;handler(e);later(()=>{pointerHandled=false},50)});element.addEventListener("click",(e)=>{if(pointerHandled){e.preventDefault();return}e.preventDefault();handler(e)})}
function bindPressAll(nodeList, handler){nodeList.forEach(el=>bindPress(el, handler))}

function maybeStartStartCardFlow(){ if(state.startCardQueue.length){ state.phase="startCardInfo"; render(); return true; } return false; }
function nextStartCardInfo(){ state.startCardQueue=[]; clearAckFlow("start-card-flow"); startNight(); }
function startGrantInfoQueue(){ const queue=[]; state.players.forEach(p=>{ if(!p.alive) return; const undelivered=p.cards.filter(c=>!c.delivered && c.source==="deathGift"); if(undelivered.length){undelivered.forEach(card=>{card.delivered=true; queue.push({playerId:p.id,type:"received",cardInstanceId:card.instanceId});}); return;} queue.push({playerId:p.id,type:"none"}); }); state.grantInfoQueue=queue; const firstAlive=state.players.find(p=>p.alive); if(firstAlive) state.selectedPlayerId=firstAlive.id; state.phase="grantInfo"; clearAckFlow("grant-card-flow"); state.transitionData={title:"Karty rozdane",message:"Przekazanie testamentów zakończone. Każdy żyjący gracz zapozna się teraz ze swoją kartą.",button:"Ok",nextPhase:"grantInfo"}; render(); }

function nextGrantInfo(){ state.grantInfoQueue=[]; clearAckFlow("grant-card-flow"); state.phase="night"; state.phaseEndsAt=Date.now()+state.settings.nightSeconds*1000; state.phaseSecondsLeft=secondsLeftFromEnd(state.phaseEndsAt); state.transitionData=null; render(); schedulePhaseTick(); }

function selectNextPlayer(){if(!state.players.length)return;const idx=Math.max(0,state.players.findIndex(p=>p.id===state.selectedPlayerId));const next=(idx+1)%state.players.length;state.selectedPlayerId=state.players[next].id;render()}
function addPlayer(){const input=document.getElementById("joinNameInput");const trimmed=input.value.trim();if(!trimmed)return;if(state.players.length>=12)return;if(state.players.some(p=>p.name.toLowerCase()===trimmed.toLowerCase()))return;state.players.push(makePlayer(trimmed));input.value="";closeJoinModal();if(!state.selectedPlayerId&&state.players[0])state.selectedPlayerId=state.players[0].id;render()}
function toggleReady(id){if(state.phase!=="lobby")return;state.players=state.players.map(p=>p.id===id?{...p,ready:!p.ready}:p);render();checkLobbyCountdown()}
function startGame(){const roles=generateRoles(state.players,state.settings);state.players=state.players.map((p,index)=>({...p,alive:true,role:roles[index],faction:roles[index]==="mafia"?"Mafia":"Miasto",roleRevealed:false,roleAcknowledged:false,ready:false,nightSubmitted:false,voteSubmitted:false,immunityActive:false,vestActive:false,doubleVoteArmed:false,teflonActive:false,ricochetArmed:false,silencedUntilDayEnd:false,intimidatedUntilNightEnd:false,cards:[]}));state.phase="roleReveal";state.rolePeekActive=false;state.winner=null;state.nightActions={};state.votes={};state.submittedVoteTargets={};state.submittedNightTargets={};state.pendingNightTargets={};state.privateNotes={};state.selectedVoteTargetId="";state.selectedNightTargetId="";state.revealEndsAt=Date.now()+30000;state.revealCountdown=secondsLeftFromEnd(state.revealEndsAt);state.roleCountdownLocked=false;state.transitionData=null;state.transitionLocked=false;state.dayReadyMap={};state.lobbyCountdown=null;state.lobbyEndsAt=null;state.roleInfoOpen=false;state.mafiaNightNotice="";dealStartCards();render();scheduleRoleRevealTick()}
function revealRole(){const sp=selectedPlayer();if(!sp)return;state.players=state.players.map(p=>p.id===sp.id?{...p,roleRevealed:true}:p);render()}
function setPeek(active){state.rolePeekActive=active;if(active)revealRole();render()}
function acknowledgeRole(){const sp=selectedPlayer();if(!sp||sp.roleAcknowledged)return;state.players=state.players.map(p=>p.id===sp.id?{...p,roleAcknowledged:true}:p);render();if(state.players.every(p=>p.roleAcknowledged||p.id===sp.id)){later(()=>{if(state.players.every(p=>p.roleAcknowledged)){state.roleCountdownLocked=true;pulseFade(()=>{ if(!maybeStartStartCardFlow()) startNight();});}},0)}}
function startNight(){state.nightOrderMap=buildPerPlayerOrder();state.phase="night";state.phaseEndsAt=Date.now()+state.settings.nightSeconds*1000;state.phaseSecondsLeft=secondsLeftFromEnd(state.phaseEndsAt);state.nightActions={};state.submittedNightTargets={};state.pendingNightTargets={};state.selectedNightTargetId="";state.activeFlashPlayerId=null;state.cardsOverlayOpen=false;state.privateNotes={};state.players=state.players.map(p=>({...p,nightSubmitted:false,voteSubmitted:false}));render();schedulePhaseTick()}
function submitNightAction(){const sp=selectedPlayer();if(!sp||!sp.alive||!state.selectedNightTargetId||sp.nightSubmitted)return;if(sp.intimidatedUntilNightEnd){state.players=state.players.map(p=>p.id===sp.id?{...p,nightSubmitted:true}:p);state.privateNotes[sp.id]="Twoja akcja nocna została zablokowana przez zastraszenie.";render();const livingPlayers=alivePlayers();const allAliveDone=livingPlayers.every(p=>p.nightSubmitted);if(allAliveDone){pulseFade(()=>resolveNightWithActions({...state.nightActions},[...state.players]))}return;}const actionType=sp.role==="mafia"?"kill":sp.role==="doctor"?"heal":sp.role==="detective"?"inspect":"dummy";state.nightActions[sp.id]={actorId:sp.id,targetId:state.selectedNightTargetId,actionType,submitted:true};if(sp.role==="mafia"){state.submittedNightTargets[sp.id]=state.selectedNightTargetId;delete state.pendingNightTargets[sp.id]}state.selectedNightTargetId="";state.players=state.players.map(p=>p.id===sp.id?{...p,nightSubmitted:true}:p);render();const livingPlayers=alivePlayers();const allAliveDone=livingPlayers.every(p=>p.nightSubmitted);if(allAliveDone){pulseFade(()=>resolveNightWithActions({...state.nightActions},[...state.players]))}}
function showTransition(data){state.transitionLocked=false;state.dayReadyMap={};state.transitionData=data;state.phase="transition";render()}
function resolveNightWithActions(actionsArg,playersArg){const basePlayers=playersArg||state.players;const actionList=Object.values(actionsArg||state.nightActions);const validActions=actionList.filter(a=>{const actor=basePlayers.find(p=>p.id===a.actorId);return actor&&actor.alive&&!actor.intimidatedUntilNightEnd});const livingMafiaIds=aliveMafiaActorIds(basePlayers).filter(id=>{const actor=basePlayers.find(p=>p.id===id);return actor&&!actor.intimidatedUntilNightEnd});const mafiaTargetId=getConsensusTargetId(Object.fromEntries(validActions.filter(a=>a.actionType==="kill").map(a=>[a.actorId,a.targetId])),livingMafiaIds);const healAction=validActions.find(a=>a.actionType==="heal");const inspectAction=validActions.find(a=>a.actionType==="inspect");let nextPlayers=basePlayers.map(p=>({...p,nightSubmitted:false,intimidatedUntilNightEnd:false}));const notes={};let killedName="Nikt";if(inspectAction){const target=nextPlayers.find(p=>p.id===inspectAction.targetId);if(target){const seenAsMafia=target.faction==="Mafia"&&!target.teflonActive;notes[inspectAction.actorId]=`${target.name} ${seenAsMafia?"jest":"nie jest"} z mafii.`;if(target.teflonActive){nextPlayers=nextPlayers.map(p=>p.id===target.id?{...p,teflonActive:false}:p);}}}if(mafiaTargetId){const target=nextPlayers.find(p=>p.id===mafiaTargetId);const saved=healAction&&healAction.targetId===mafiaTargetId;const hasVest=target&&target.vestActive;if(target&&!saved&&!hasVest){nextPlayers=nextPlayers.map(p=>p.id===target.id?{...p,alive:false}:p);killedName=target.name}else if(target&&hasVest){nextPlayers=nextPlayers.map(p=>p.id===target.id?{...p,vestActive:false}:p);killedName="Nikt";notes[target.id]="Kamizelka ochroniła Cię przed atakiem."}}state.players=nextPlayers;state.privateNotes=notes;state.mafiaNightNotice="";state.selectedNightTargetId="";state.pendingNightTargets={};state.activeFlashPlayerId=null;const maybeWinner=getWinner(nextPlayers);if(maybeWinner){pulseFade(()=>{state.winner=maybeWinner;state.phase="ended";render()});return}showTransition({title:"Nastał dzień",message:killedName==="Nikt"?"Tej nocy nikt nie zginął.":`${killedName}
${targetGenderText(killedName,"został wyeliminowany","została wyeliminowana")}
przez mafię.`,button:"Ok",nextPhase:"day"})}
function resolveNight(){resolveNightWithActions()}
function startVoting(){state.voteOrderMap=buildPerPlayerOrder();state.phase="voting";state.phaseEndsAt=Date.now()+state.settings.votingSeconds*1000;state.phaseSecondsLeft=secondsLeftFromEnd(state.phaseEndsAt);state.votes={};state.submittedVoteTargets={};state.selectedVoteTargetId="";state.activeFlashPlayerId=null;state.cardsOverlayOpen=false;state.players=state.players.map(p=>({...p,voteSubmitted:false}));render();schedulePhaseTick()}
function submitVote(){const sp=selectedPlayer();if(!sp||!sp.alive||sp.silencedUntilDayEnd||!state.selectedVoteTargetId||sp.voteSubmitted)return;state.votes[sp.id]=state.selectedVoteTargetId;state.submittedVoteTargets[sp.id]=state.selectedVoteTargetId;state.players=state.players.map(p=>p.id===sp.id?{...p,voteSubmitted:true}:p);render();const livingPlayers=alivePlayers();const allAliveDone=livingPlayers.every(p=>p.voteSubmitted);if(allAliveDone){pulseFade(()=>resolveVoting())}}
function resolveVoting(){const counts={};Object.entries(state.votes).forEach(([actorId,targetId])=>{const actor=state.players.find(p=>p.id===actorId);const weight=actor&&actor.doubleVoteArmed?2:1;counts[targetId]=(counts[targetId]||0)+weight});const ranked=Object.entries(counts).sort((a,b)=>b[1]-a[1]);let nextPlayers=state.players.map(p=>({...p,voteSubmitted:false,doubleVoteArmed:false,silencedUntilDayEnd:false}));let eliminatedName="Nikt";let eliminatedId=null;if(ranked.length===1||(ranked.length>1&&ranked[0][1]>ranked[1][1])){eliminatedId=ranked[0][0];if(ranked.length>1&&nextPlayers.some(p=>p.ricochetArmed&&p.alive)){const secondId=ranked[1][0];nextPlayers=nextPlayers.map(p=>p.ricochetArmed?{...p,ricochetArmed:false}:p);eliminatedId=secondId;}const protectedTarget=nextPlayers.find(p=>p.id===eliminatedId&&p.immunityActive);if(protectedTarget){nextPlayers=nextPlayers.map(p=>p.id===eliminatedId?{...p,immunityActive:false}:p);eliminatedId=null;eliminatedName="Nikt";}else{nextPlayers=nextPlayers.map(p=>p.id===eliminatedId?{...p,alive:false}:p);const eliminated=nextPlayers.find(p=>p.id===eliminatedId);if(eliminated)eliminatedName=eliminated.name}}state.players=nextPlayers;state.selectedVoteTargetId="";state.activeFlashPlayerId=null;const maybeWinner=getWinner(nextPlayers);if(maybeWinner){pulseFade(()=>{state.winner=maybeWinner;state.phase="ended";render()});return}
 const deadPlayers=state.players.filter(p=>!p.alive);const aliveTargets=state.players.filter(p=>p.alive);if(state.settings.enableCards&&activeCardPool().length&&deadPlayers.length&&aliveTargets.length){const pool=activeCardPool();deadPlayers.forEach(dead=>{dead.cards=[];const cardMeta=pool[Math.floor(Math.random()*pool.length)];dead.cards.push(createCardInstance(cardMeta.key,"death"));});const queue=deadPlayers.map(p=>p.id);const firstId=queue.shift();const firstDead=state.players.find(p=>p.id===firstId);const firstCard=firstDead&&firstDead.cards[0];if(firstDead&&firstCard){state.deathGiftQueue=queue;state.awaitingDeathGiftFor={deadPlayerId:firstId,cardInstanceId:firstCard.instanceId};state.deathGiftTargetId="";state.deathGiftSelectingTarget=false;showTransition({title:"Wynik głosowania",message:eliminatedName==="Nikt"?"Brak nowej eliminacji.":`${eliminatedName}
${targetGenderText(eliminatedName,"został wyeliminowany","została wyeliminowana")}.`,button:"Dalej",nextPhase:"deathGiftChoose"});return;}}
 showTransition({title:"Wynik głosowania",message:eliminatedName==="Nikt"?"Brak eliminacji.":`${eliminatedName}
${targetGenderText(eliminatedName,"został wyeliminowany","została wyeliminowana")}.`,button:"Ok",nextPhase:"night"})}

function handleTransitionConfirm(){if(!state.transitionData||state.transitionLocked)return;state.transitionLocked=true;render();pulseFade(()=>{const next=state.transitionData.nextPhase;state.transitionData=null;state.transitionLocked=false;if(next==="day"){state.phase="day";state.phaseEndsAt=Date.now()+state.settings.daySeconds*1000;state.phaseSecondsLeft=secondsLeftFromEnd(state.phaseEndsAt);render();schedulePhaseTick()}else if(next==="night"){startNight()}else if(next==="grantInfo"){state.phase="grantInfo";render()}else if(next==="deathGiftChoose"){state.phase="deathGiftChoose";render()}else{state.phase="ended";render()}})}

function handleTransitionConfirm(){if(!state.transitionData||state.transitionLocked)return;state.transitionLocked=true;render();pulseFade(()=>{const next=state.transitionData.nextPhase;state.transitionData=null;state.transitionLocked=false;if(next==="day"){state.phase="day";state.phaseEndsAt=Date.now()+state.settings.daySeconds*1000;state.phaseSecondsLeft=secondsLeftFromEnd(state.phaseEndsAt);render();schedulePhaseTick()}else if(next==="night"){startNight()}else if(next==="grantInfo"){state.phase="grantInfo";render()}else{state.phase="ended";render()}})}
function markReadyForVoting(){const sp=selectedPlayer();if(!sp||!sp.alive)return;state.dayReadyMap[sp.id]=true;render();const livingPlayers=alivePlayers();if(livingPlayers.every(p=>state.dayReadyMap[p.id])){pulseFade(()=>startVoting())}}
function resetGame(){state.players=state.players.map(p=>makePlayer(p.name));state.selectedPlayerId=state.players[0]?state.players[0].id:"";state.phase="lobby";state.lobbyCountdown=null;state.lobbyEndsAt=null;state.rolePeekActive=false;state.revealCountdown=30;state.revealEndsAt=null;state.roleCountdownLocked=false;state.phaseSecondsLeft=state.settings.daySeconds;state.phaseEndsAt=null;state.nightActions={};state.votes={};state.submittedVoteTargets={};state.submittedNightTargets={};state.pendingNightTargets={};state.privateNotes={};state.winner=null;state.selectedVoteTargetId="";state.selectedNightTargetId="";state.transitionData=null;state.transitionLocked=false;state.dayReadyMap={};state.nightOrderMap={};state.voteOrderMap={};state.activeFlashPlayerId=null;state.cardsOverlayOpen=false;state.selectedCardIndex=0;state.cardPeekActive=false;state.startCardQueue=[];state.grantInfoQueue=[];state.deathGiftQueue=[];state.awaitingDeathGiftFor=null;state.deathGiftTargetId="";state.deathGiftSelectingTarget=false;state.cardTargetContext=null;state.roleInfoOpen=false;state.mafiaNightNotice="";state.ackFlows={};state.currentAckKey="";clearAllTimers();render()}
function checkLobbyCountdown(){if(state.phase!=="lobby")return;const readyCount=state.players.filter(p=>p.ready).length;const everyoneReady=state.players.length>=4&&readyCount===state.players.length;if(!everyoneReady){state.lobbyCountdown=null;state.lobbyEndsAt=null;render();return}if(state.lobbyEndsAt!==null)return;state.lobbyEndsAt=Date.now()+3000;state.lobbyCountdown=secondsLeftFromEnd(state.lobbyEndsAt);render();const tick=()=>{if(state.phase!=="lobby"||state.lobbyEndsAt===null)return;const remaining=secondsLeftFromEnd(state.lobbyEndsAt);state.lobbyCountdown=remaining;render();if(remaining<=0){pulseFade(()=>{state.lobbyCountdown=null;state.lobbyEndsAt=null;startGame()});return}later(tick,250)};later(tick,250)}
function scheduleRoleRevealTick(){const tick=()=>{if(state.phase!=="roleReveal")return;if(state.roleCountdownLocked)return;if(!state.revealEndsAt)return;const remaining=secondsLeftFromEnd(state.revealEndsAt);state.revealCountdown=remaining;render();if(remaining<=0){state.roleCountdownLocked=true;pulseFade(()=>{if(!maybeStartStartCardFlow()) startNight()});return}later(tick,250)};later(tick,250)}
function schedulePhaseTick(){const tick=()=>{if(!["night","day","voting"].includes(state.phase))return;if(state.transitionData)return;if(!state.phaseEndsAt)return;const remaining=secondsLeftFromEnd(state.phaseEndsAt);state.phaseSecondsLeft=remaining;render();if(remaining<=0){if(state.phase==="night")resolveNight();else if(state.phase==="day")startVoting();else if(state.phase==="voting")resolveVoting();return}later(tick,250)};later(tick,250)}
function userIconSVG(size=16){return `<svg viewBox="0 0 24 24" width="${size}" height="${size}" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M20 21a8 8 0 0 0-16 0"></path><circle cx="12" cy="7" r="4"></circle></svg>`}
function eyeIconSVG(size=64){return `<svg viewBox="0 0 24 24" width="${size}" height="${size}" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M2 12s3.5-6 10-6 10 6 10 6-3.5 6-10 6S2 12 2 12Z"></path><circle cx="12" cy="12" r="3"></circle></svg>`}
function crosshairIconText(){return `<svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="display:block"><circle cx="12" cy="12" r="6"></circle><path d="M12 3v3"></path><path d="M12 18v3"></path><path d="M3 12h3"></path><path d="M18 12h3"></path></svg>`}
function tileHTML(player,opts={}){const{showReady=false,voteCount=0,pendingCount=0,disabled=false,flash=false,muted=false,pendingTarget=false,showPlus=false}=opts;if(showPlus){return `<button class="tile" data-plus="1"><div class="tile-left"><span style="display:flex;align-items:center;justify-content:center">${userIconSVG(14)}</span><span class="tile-name">Dołącz</span></div></button>`}if(!player)return "";const extraClasses=[disabled?"disabled":"",flash?"flash":"",muted?"is-muted":"",muted?"dead":""].join(" ");return `<button class="tile ${extraClasses}" data-player-id="${player.id}" ${disabled?"disabled":""}><div class="tile-left"><span style="display:flex;align-items:center;justify-content:center">${userIconSVG(14)}</span><span class="tile-name">${player.name}</span></div><div class="tile-right">${pendingTarget&&pendingCount>0?`<span class="pending">${crosshairIconText()} <span>${pendingCount}</span></span>`:""}${voteCount>0?`<span class="count">${voteCount}</span>`:""}${showReady&&player.ready?`<span class="count">✓</span>`:""}</div></button>`}
function canOpenCards(player){return !!player&&player.cards.some(card=>!card.used)}
function bottomHTML({metaLines=["&nbsp;"],secondaryLabel="Karty",secondaryDisabled=true,secondaryVisible=true,secondaryId="secondaryBtn",primaryLabel="Ok",primaryDisabled=false,primaryId="mainBtn"}){const secondary=secondaryVisible?`<button id="${secondaryId}" class="text-action" ${secondaryDisabled?"disabled":""}>${secondaryLabel}</button>`:`<div class="text-action text-action-placeholder" aria-hidden="true"></div>`;return `<div class="bottom"><div class="bottom-meta">${metaLines.map(line=>`<div class="bottom-meta-line">${line}</div>`).join("")}</div><div class="bottom-secondary-slot">${secondary}</div><button id="${primaryId}" class="primary" ${primaryDisabled?"disabled":""}>${primaryLabel}</button></div>`}
