function renderNight(screen,sp){const order=state.nightOrderMap[sp.id]||state.players;const isDead=!sp.alive;const alreadySubmitted=!!sp.nightSubmitted;const hasCards=canOpenCards(sp);const blocked=!!sp.intimidatedUntilNightEnd;const title=sp.role==="mafia"?"Wybierz osobę do eliminacji":sp.role==="doctor"?"Wybierz osobę do ochrony":sp.role==="detective"?"Wybierz osobę do sprawdzenia":"Kogo podejrzewasz?";let statusNote=blocked?"Tej nocy Twoja akcja jest zablokowana.":"&nbsp;";if(sp.role==="mafia"&&state.mafiaNightNotice){statusNote=state.mafiaNightNotice;}const nightCounts=countTargetsFromActors(state.submittedNightTargets,mafiaActorIds());const pendingNightCounts=countTargetsFromActors(state.pendingNightTargets,mafiaActorIds());screen.innerHTML=`<div class="title-top">Noc</div><div class="timer">${formatSeconds(state.phaseSecondsLeft)}</div><div class="info-text">${isDead?"Nie żyjesz, nie bierzesz udziału w akcji nocnej":alreadySubmitted?"Twój wybór został już zatwierdzony":title}</div><div class="grid" id="nightGrid"></div>${bottomHTML({metaLines:[statusNote],secondaryLabel:"Karty",secondaryDisabled:false,secondaryVisible:hasCards,primaryLabel:"Gotowe",primaryDisabled:isDead||alreadySubmitted||blocked||!state.selectedNightTargetId})}`;const grid=document.getElementById("nightGrid");grid.innerHTML=order.map((player)=>{const detectiveSelfBlocked=sp.role==="detective"&&player.id===sp.id;const hardDisabled=isDead||!player.alive||alreadySubmitted||blocked;const muted=isDead||!player.alive||alreadySubmitted||blocked;const disabled=hardDisabled||detectiveSelfBlocked;return tileHTML(player,{voteCount:sp.role==="mafia"&&!isDead?(nightCounts[player.id]||0):0,pendingCount:sp.role==="mafia"&&!isDead?(pendingNightCounts[player.id]||0):0,pendingTarget:sp.role==="mafia"&&!isDead&&(pendingNightCounts[player.id]||0)>0,flash:state.activeFlashPlayerId===player.id,muted,disabled})}).join("");bindPressAll(grid.querySelectorAll("[data-player-id]"),(e)=>{if(alreadySubmitted||isDead||blocked)return;const id=e.currentTarget.getAttribute("data-player-id");const target=state.players.find((p)=>p.id===id);if(!target||!target.alive)return;if(sp.role==="detective"&&id===sp.id)return;chooseAndFlashPlayer(id,(value)=>{state.selectedNightTargetId=value;render()},(value)=>{if(sp.role==="mafia"&&!sp.nightSubmitted){state.pendingNightTargets[sp.id]=value;render()}})});bindCardsShortcut(sp);bindPress(document.getElementById("mainBtn"),()=>submitNightAction());if(state.cardsOverlayOpen) renderCardsOverlay(screen, sp)}

function renderDay(screen,sp){const livingPlayers=alivePlayers();const isDead=!sp.alive;const hasCards=canOpenCards(sp);const readyCount=livingPlayers.filter((p)=>state.dayReadyMap[p.id]).length;screen.innerHTML=`<div class="title-top">Obrady</div><div class="timer">${formatSeconds(state.phaseSecondsLeft)}</div><div class="info-text" style="flex:1;display:flex;align-items:center;justify-content:center;padding:0 18px">${isDead?"Nie żyjesz, nie bierzesz udziału w obradach i głosowaniu.":"Trwają obrady, ustalcie wspólnie kto jest członkiem mafii."}</div>${bottomHTML({metaLines:[`${readyCount}/${livingPlayers.length}`],secondaryLabel:"Karty",secondaryDisabled:false,secondaryVisible:hasCards,primaryLabel:"Do głosowania",primaryDisabled:!sp||isDead||state.dayReadyMap[sp.id]})}`;bindCardsShortcut(sp);bindPress(document.getElementById("mainBtn"),()=>markReadyForVoting());if(state.cardsOverlayOpen) renderCardsOverlay(screen, sp)}
function renderVoting(screen,sp){const order=state.voteOrderMap[sp.id]||state.players;const isDead=!sp.alive;const blocked=!!sp.silencedUntilDayEnd;const hasCards=canOpenCards(sp);const voteCounts=Object.entries(state.submittedVoteTargets).reduce((acc,[actorId,id])=>{const actor=state.players.find(p=>p.id===actorId);const weight=actor&&actor.doubleVoteArmed?2:1;acc[id]=(acc[id]||0)+weight;return acc},{}) ;let statusNote="&nbsp;";if(blocked)statusNote="Zostałeś wykluczony z głosowania.";else if(sp.doubleVoteArmed)statusNote="Twój głos liczy się podwójnie.";screen.innerHTML=`<div class="title-top">Głosowanie</div><div class="timer">${formatSeconds(state.phaseSecondsLeft)}</div><div class="info-text">${isDead?"Nie żyjesz, nie bierzesz udziału w głosowaniu":blocked?"W tej rundzie nie możesz głosować":"Twoja kolej na oddanie głosu"}</div><div class="grid" id="voteGrid"></div>${bottomHTML({metaLines:[statusNote],secondaryLabel:"Karty",secondaryDisabled:false,secondaryVisible:hasCards,primaryLabel:"Gotowe",primaryDisabled:isDead||blocked||sp.voteSubmitted||!state.selectedVoteTargetId})}`;const grid=document.getElementById("voteGrid");grid.innerHTML=order.map((player)=>{const playerDisabled=!player.alive||isDead||blocked;const playerMuted=!player.alive||isDead||blocked;return tileHTML(player,{voteCount:voteCounts[player.id]||0,flash:player.alive&&state.activeFlashPlayerId===player.id,muted:playerMuted,disabled:playerDisabled})}).join("");bindPressAll(grid.querySelectorAll("[data-player-id]"),(e)=>{if(isDead||blocked||sp.voteSubmitted)return;const id=e.currentTarget.getAttribute("data-player-id");const target=state.players.find((p)=>p.id===id);if(!target||!target.alive)return;chooseAndFlashPlayer(id,(value)=>{state.selectedVoteTargetId=value;render()})});bindCardsShortcut(sp);bindPress(document.getElementById("mainBtn"),()=>submitVote());if(state.cardsOverlayOpen) renderCardsOverlay(screen, sp)}
function cardNeedsTarget(cardKey){return ["blackmail","privateDetective","silence","steal","sniper","intimidation","search"].includes(cardKey)}
function validTargetsForCard(player, card){if(!player||!card)return[];const others=state.players.filter(p=>p.alive&&p.id!==player.id);if(card.key==="steal") return others.filter(p=>p.cards.some(c=>!c.used));return others}
function openCardTargeting(player, card){const candidates=validTargetsForCard(player, card);if(!candidates.length)return false;state.cardTargetContext={actorId:player.id,cardInstanceId:card.instanceId,targetId:""};return true}

function applyCardEffect(player, card, targetId){if(!player||!card||card.used)return {ok:false};const target=targetId?state.players.find(p=>p.id===targetId&&p.alive):null;if(card.key==="immunity"){state.players=state.players.map(p=>p.id===player.id?{...p,immunityActive:true}:p);return {ok:true,note:"Immunitet aktywny: najbliższy lincz zostanie anulowany."};}if(card.key==="doubleVote"){state.players=state.players.map(p=>p.id===player.id?{...p,doubleVoteArmed:true}:p);return {ok:true,note:"Podwójny głos aktywny na to głosowanie."};}if(card.key==="vest"){state.players=state.players.map(p=>p.id===player.id?{...p,vestActive:true}:p);return {ok:true,note:"Kamizelka aktywna: pierwszy nocny atak nie zabije."};}if(card.key==="ricochet"){state.players=state.players.map(p=>p.id===player.id?{...p,ricochetArmed:true}:p);return {ok:true,note:"Kozioł ofiarny aktywny: lincz może przeskoczyć na drugie miejsce."};}if(card.key==="blackmail"){if(!target)return {ok:false,note:"Wybierz cel szantażu."};state.votes[target.id]=state.selectedVoteTargetId||player.id;state.submittedVoteTargets[target.id]=state.votes[target.id];return {ok:true,note:`Szantaż: ${target.name} odda głos zgodny z Twoim wskazaniem.`};}if(card.key==="privateDetective"){if(!target)return {ok:false,note:"Wybierz cel sprawdzenia."};const seenAsMafia=target.faction==="Mafia"&&!target.teflonActive;return {ok:true,note:`Prywatny detektyw: ${target.name} ${seenAsMafia?"jest":"nie jest"} z mafii.`};}if(card.key==="silence"){if(!target)return {ok:false,note:"Wybierz kogo uciszyć."};state.players=state.players.map(p=>p.id===target.id?{...p,silencedUntilDayEnd:true}:p);return {ok:true,note:`Nakaz milczenia: ${target.name} jest wykluczony z głosowania do końca dnia.`};}if(card.key==="steal"){if(!target)return {ok:false,note:"Wybierz ofiarę kradzieży."};const available=target.cards.filter(c=>!c.used);const stolen=available[Math.floor(Math.random()*available.length)];if(!stolen)return {ok:false,note:"Ten gracz nie ma karty do kradzieży."};state.players=state.players.map(p=>{if(p.id===target.id){return {...p,cards:p.cards.filter(c=>c.instanceId!==stolen.instanceId)}}if(p.id===player.id){return {...p,cards:[...p.cards,{...stolen,source:"stolen"}]}}return p});return {ok:true,note:`Kradzież udana: przejęto kartę od ${target.name}.`};}if(card.key==="teflon"){state.players=state.players.map(p=>p.id===player.id?{...p,teflonActive:true}:p);return {ok:true,note:"Fałszywe alibi aktywne: detektyw zobaczy Cię jako Miasto."};}if(card.key==="sniper"){if(!["day","voting"].includes(state.phase))return {ok:false,note:"Snajpera można użyć tylko za dnia lub podczas głosowania."};if(!target)return {ok:false,note:"Wybierz cel snajpera."};state.players=state.players.map(p=>p.id===target.id?{...p,alive:false}:p);return {ok:true,note:`Snajper: ${target.name} został natychmiast wyeliminowany.`};}if(card.key==="intimidation"){if(!target)return {ok:false,note:"Wybierz cel zastraszenia."};state.players=state.players.map(p=>p.id===target.id?{...p,intimidatedUntilNightEnd:true}:p);return {ok:true,note:`Zastraszenie: ${target.name} straci najbliższą akcję nocną.`};}if(card.key==="search"){if(!target)return {ok:false,note:"Wybierz cel rewizji."};const cardFound=target.cards.find(c=>!c.used)||target.cards[0];if(!cardFound)return {ok:true,note:`Rewizja: ${target.name} nie ma żadnych kart.`};const meta=cardFound.meta||SPECIAL_CARDS.find(c=>c.key===cardFound.key);return {ok:true,note:`Rewizja: u ${target.name} znaleziono kartę "${meta?meta.name:cardFound.key}".`};}if(card.key==="convert"){const self=state.players.find(p=>p.id===player.id);if(!self)return {ok:false,note:"Nie znaleziono gracza."};const goingToMafia=self.faction!=="Mafia";state.players=state.players.map(p=>p.id===player.id?{...p,faction:goingToMafia?"Mafia":"Miasto",role:goingToMafia?"mafia":"citizen"}:p);if(goingToMafia){const msg=`${player.name} gra od teraz z Wami.`;state.mafiaNightNotice=msg;}return {ok:true,note:`Zmiana stron: przechodzisz na stronę ${goingToMafia?"Mafii":"Miasta"}.`};}return {ok:false,note:"Ta karta jeszcze nie ma efektu."};}
function randomAliveTarget(excludeId){const candidates=state.players.filter(p=>p.alive&&p.id!==excludeId);if(!candidates.length)return null;return candidates[Math.floor(Math.random()*candidates.length)]||null;}
function skipCurrentPhase(){if(state.transitionData){handleTransitionConfirm();return;}if(state.phase==="lobby"){state.players=state.players.map(p=>({...p,ready:true}));checkLobbyCountdown();return;}if(state.phase==="roleReveal"){state.players=state.players.map(p=>({...p,roleAcknowledged:true}));if(!maybeStartStartCardFlow())startNight();return;}if(state.phase==="startCardInfo"){nextStartCardInfo();return;}if(state.phase==="deathGiftChoose"){const target=randomAliveTarget(null);if(target){transferCurrentDeathGift(target.id);render();return;}startGrantInfoQueue();return;}if(state.phase==="grantInfo"){nextGrantInfo();return;}if(state.phase==="day"){alivePlayers().forEach(p=>{state.dayReadyMap[p.id]=true});pulseFade(()=>startVoting());return;}if(state.phase==="night"){const living=alivePlayers();living.forEach(actor=>{if(actor.nightSubmitted)return;if(actor.intimidatedUntilNightEnd){state.players=state.players.map(p=>p.id===actor.id?{...p,nightSubmitted:true}:p);return;}const fallback=randomAliveTarget(null);const target=randomAliveTarget(actor.role==="detective"?actor.id:null)||fallback;if(!target)return;const actionType=actor.role==="mafia"?"kill":actor.role==="doctor"?"heal":actor.role==="detective"?"inspect":"dummy";state.nightActions[actor.id]={actorId:actor.id,targetId:target.id,actionType,submitted:true};if(actor.role==="mafia"){state.submittedNightTargets[actor.id]=target.id;delete state.pendingNightTargets[actor.id];}});state.players=state.players.map(p=>p.alive?{...p,nightSubmitted:true}:p);pulseFade(()=>resolveNightWithActions({...state.nightActions},[...state.players]));return;}if(state.phase==="voting"){const living=alivePlayers();living.forEach(actor=>{if(actor.voteSubmitted||actor.silencedUntilDayEnd)return;const target=randomAliveTarget(actor.id)||randomAliveTarget(null);if(!target)return;state.votes[actor.id]=target.id;state.submittedVoteTargets[actor.id]=target.id;});state.players=state.players.map(p=>p.alive?{...p,voteSubmitted:true}:p);pulseFade(()=>resolveVoting());return;}}
function renderCardsOverlay(screen, sp){const cards=sp.cards.filter(c=>!c.used); if(!cards.length) return; const selected=cards[Math.min(state.selectedCardIndex,cards.length-1)]||null; const hasTargetStep=state.cardTargetContext&&state.cardTargetContext.actorId===sp.id&&state.cardTargetContext.cardInstanceId===selected?.instanceId; const candidates=selected?validTargetsForCard(sp,selected):[]; const canPlay=!!selected && selected.meta && selected.meta.implemented && canUseCard(selected,sp); const phaseOrScopeError=selected?cardUseError(selected,sp):""; let message=phaseOrScopeError|| (selected && !selected.meta.implemented ? 'Efekt tej karty nie jest jeszcze wdrożony.' : cardNeedsTarget(selected?.key)?'Ta karta wymaga wskazania celu po kliknięciu Zagraj.':'&nbsp;'); screen.insertAdjacentHTML('beforeend', `<div class="fullscreen-overlay" id="cardsOverlay"><div class="title-top">Schowek kart</div><div class="fullscreen-overlay-center"><div style="width:100%"><div class="card-slider-single">${selected?`<div class="card-slide selected" data-card-index="${Math.min(state.selectedCardIndex,cards.length-1)}">${cardFaceHTML(selected)}</div>`:''}</div>${cards.length>1?`<div class="card-thumb-slider" id="cardThumbSlider">${cards.map((card,index)=>`<button class="card-thumb ${index===Math.min(state.selectedCardIndex,cards.length-1)?'active':''}" data-card-index="${index}">${index+1}</button>`).join('')}</div>`:''}<div class="card-selected-indicator">${cards.length ? `${Math.min(state.selectedCardIndex+1,cards.length)}/${cards.length}` : ''}</div></div></div>${bottomHTML({metaLines:[message],secondaryLabel:"Wróć",secondaryDisabled:false,secondaryId:"backFromCardsBtn",primaryLabel:hasTargetStep?"Wybierz cel":"Zagraj",primaryDisabled:!canPlay||(cardNeedsTarget(selected?.key)&&!candidates.length),primaryId:"playCardBtn"})}</div>`); const thumbs=document.querySelectorAll('#cardThumbSlider .card-thumb'); bindPressAll(thumbs,(e)=>{state.selectedCardIndex=Number(e.currentTarget.getAttribute('data-card-index')||0);state.cardTargetContext=null; render()}); bindPress(document.getElementById('backFromCardsBtn'),()=>{state.cardsOverlayOpen=false;state.cardTargetContext=null;render()}); bindPress(document.getElementById('playCardBtn'),()=>{ if(!canPlay) return; if(cardNeedsTarget(selected.key)){if(!openCardTargeting(sp,selected)){state.privateNotes[sp.id]='Brak dostępnych celów dla tej karty.';render();return;} render(); return;} const result=applyCardEffect(sp,selected); if(result&&result.note){state.privateNotes[sp.id]=result.note;} if(result&&result.ok){selected.used=true; state.cardsOverlayOpen=false; state.cardTargetContext=null;} render(); }); if(hasTargetStep){screen.insertAdjacentHTML('beforeend', `<div class="fullscreen-overlay" id="cardTargetOverlay"><div class="title-top">Wybierz cel karty</div><div class="info-text">Kliknij gracza, na którego chcesz zagrać kartę.</div><div class="grid" id="cardTargetGrid">${state.players.map(player=>{const enabled=candidates.some(c=>c.id===player.id);return tileHTML(player,{muted:!enabled,disabled:!enabled,flash:state.activeFlashPlayerId===player.id});}).join('')}</div>${bottomHTML({metaLines:['&nbsp;'],secondaryLabel:'Anuluj',secondaryId:'cancelCardTargetBtn',primaryLabel:'Potwierdź',primaryDisabled:!state.cardTargetContext.targetId,primaryId:'confirmCardTargetBtn'})}</div>`);const targetGrid=document.getElementById('cardTargetGrid');bindPressAll(targetGrid.querySelectorAll('[data-player-id]'),(e)=>{const id=e.currentTarget.getAttribute('data-player-id');if(!candidates.some(c=>c.id===id))return;chooseAndFlashPlayer(id,(value)=>{state.cardTargetContext.targetId=value;render()});});bindPress(document.getElementById('cancelCardTargetBtn'),()=>{state.cardTargetContext=null;render()});bindPress(document.getElementById('confirmCardTargetBtn'),()=>{const ctx=state.cardTargetContext;if(!ctx||!ctx.targetId)return;const result=applyCardEffect(sp,selected,ctx.targetId);if(result&&result.note){state.privateNotes[sp.id]=result.note;}if(result&&result.ok){selected.used=true;state.cardsOverlayOpen=false;state.cardTargetContext=null;}render();}); }}

function renderTransition(screen){const data=state.transitionData;const ackKey=`transition-${data.title}-${data.nextPhase}`;ensureAckFlow(ackKey);const sp=selectedPlayer();const alreadyAcked=isAckedInFlow(ackKey,sp.id);const privateNote=state.privateNotes[sp.id];screen.innerHTML=`<div class="transition-box"><div class="title-top">${data.title}</div><div style="flex:1;display:flex;align-items:center;justify-content:center"><div><div class="transition-message">${data.message.replace(/\n/g,"<br>")}</div>${privateNote?`<div class="transition-note">${privateNote}</div>`:""}</div></div></div>${bottomHTML({metaLines:[ackCountTextByKey(ackKey)],secondaryVisible:false,primaryLabel:data.button,primaryDisabled:alreadyAcked})}`;bindPress(document.getElementById("mainBtn"),()=>{acknowledgeFlow(ackKey,()=>handleTransitionConfirm())})}
function renderEnd(screen){screen.innerHTML=`<div class="title-top">Koniec gry</div><div style="margin-top:16px;text-align:center;font-size:34px;font-weight:700">Wygrywa ${state.winner||"—"}</div><div id="endGrid" class="end-grid"></div>${bottomHTML({metaLines:["&nbsp;"],secondaryVisible:false,primaryLabel:"Nowa gra"})}`;const endGrid=document.getElementById("endGrid");endGrid.innerHTML=state.players.map((player)=>{const roleClass=player.role?ROLE_META[player.role].endColor:"white";return `<div class="end-tile ${roleClass}"><div class="tile-left"><span style="display:flex;align-items:center;justify-content:center">${userIconSVG(14)}</span><span class="tile-name">${player.name}</span></div></div>`}).join("");bindPress(document.getElementById("mainBtn"),()=>resetGame())}
function renderSettings(){const wrap=document.getElementById('settingsGrid'); wrap.innerHTML=`<label class="settings-row"><span>Liczba mafiozów</span><div class="settings-inline"><button id="mafMinus" class="small-btn">-</button><span class="settings-value">${state.settings.mafiaCount}</span><button id="mafPlus" class="small-btn">+</button></div></label><label class="settings-row"><span>Karty na start</span><div class="settings-inline"><button id="cardMinus" class="small-btn">-</button><span class="settings-value">${state.settings.startCardsCount}</span><button id="cardPlus" class="small-btn">+</button></div></label><label class="settings-row"><span>Czas dnia</span><div class="settings-inline"><button id="dayMinus" class="small-btn">-</button><span class="settings-value">${formatSeconds(state.settings.daySeconds)}</span><button id="dayPlus" class="small-btn">+</button></div></label><label class="settings-row"><span>Czas głosowania</span><div class="settings-inline"><button id="voteMinus" class="small-btn">-</button><span class="settings-value">${formatSeconds(state.settings.votingSeconds)}</span><button id="votePlus" class="small-btn">+</button></div></label><label class="settings-row"><span>Czas nocy</span><div class="settings-inline"><button id="nightMinus" class="small-btn">-</button><span class="settings-value">${formatSeconds(state.settings.nightSeconds)}</span><button id="nightPlus" class="small-btn">+</button></div></label><label class="settings-row"><span>Włącz karty</span><input id="cardsToggle" type="checkbox" ${state.settings.enableCards?'checked':''}></label><label class="settings-row"><span>Lekarz</span><input id="doctorToggle" type="checkbox" ${state.settings.enableDoctor?'checked':''}></label><label class="settings-row"><span>Detektyw</span><input id="detectiveToggle" type="checkbox" ${state.settings.enableDetective?'checked':''}></label><div class="helper-note">Aktywne karty</div>${SPECIAL_CARDS.map(card=>`<label class="settings-row"><span>${card.name}</span><input class="card-setting" data-key="${card.key}" type="checkbox" ${state.settings.enabledCards[card.key]?'checked':''}></label>`).join('')}<div class="modal-actions"><button id="settingsCloseBtn" class="primary">Zamknij</button></div>`;
 bindPress(document.getElementById('mafMinus'),()=>{state.settings.mafiaCount=Math.max(1,state.settings.mafiaCount-1);resetReady();render()}); bindPress(document.getElementById('mafPlus'),()=>{state.settings.mafiaCount=Math.min(5,state.settings.mafiaCount+1);resetReady();render()}); bindPress(document.getElementById('cardMinus'),()=>{state.settings.startCardsCount=Math.max(0,state.settings.startCardsCount-1);resetReady();render()}); bindPress(document.getElementById('cardPlus'),()=>{state.settings.startCardsCount=Math.min(12,state.settings.startCardsCount+1);resetReady();render()}); bindPress(document.getElementById('dayMinus'),()=>{state.settings.daySeconds=Math.max(30,state.settings.daySeconds-15);resetReady();render()}); bindPress(document.getElementById('dayPlus'),()=>{state.settings.daySeconds=Math.min(900,state.settings.daySeconds+15);resetReady();render()}); bindPress(document.getElementById('voteMinus'),()=>{state.settings.votingSeconds=Math.max(10,state.settings.votingSeconds-5);resetReady();render()}); bindPress(document.getElementById('votePlus'),()=>{state.settings.votingSeconds=Math.min(300,state.settings.votingSeconds+5);resetReady();render()}); bindPress(document.getElementById('nightMinus'),()=>{state.settings.nightSeconds=Math.max(15,state.settings.nightSeconds-5);resetReady();render()}); bindPress(document.getElementById('nightPlus'),()=>{state.settings.nightSeconds=Math.min(600,state.settings.nightSeconds+5);resetReady();render()}); document.getElementById('cardsToggle').onchange=(e)=>{state.settings.enableCards=e.target.checked;resetReady()}; document.getElementById('doctorToggle').onchange=(e)=>{state.settings.enableDoctor=e.target.checked;resetReady()}; document.getElementById('detectiveToggle').onchange=(e)=>{state.settings.enableDetective=e.target.checked;resetReady()}; wrap.querySelectorAll('.card-setting').forEach(el=>el.addEventListener('change',(e)=>{state.settings.enabledCards[e.target.getAttribute('data-key')]=e.target.checked;resetReady()})); bindPress(document.getElementById('settingsCloseBtn'),()=>closeSettingsModal()) }
function render(){if(!state.selectedPlayerId&&state.players[0])state.selectedPlayerId=state.players[0].id;const sp=selectedPlayer();document.getElementById("testInfo").textContent=sp?`${sp.name} • ${sp.alive?"żyje":"martwy"} • ${sp.role?ROLE_META[sp.role].name:"brak roli"}`:"Brak aktywnego gracza";renderSettings();const screen=document.getElementById("screen");if(!sp&&state.phase!=="lobby"){screen.innerHTML="";return} if(state.phase==="grantInfo" && sp && !sp.alive){ nextGrantInfo(); return; } if(state.transitionData) renderTransition(screen); else if(state.phase==="lobby") renderLobby(screen,sp); else if(state.phase==="roleReveal") renderRoleReveal(screen,sp); else if(state.phase==="startCardInfo") renderCardInfo(screen,sp); else if(state.phase==="deathGiftChoose") renderDeathGiftChoose(screen,sp); else if(state.phase==="grantInfo") renderGrantInfo(screen,sp); else if(state.phase==="night") renderNight(screen,sp); else if(state.phase==="day") renderDay(screen,sp); else if(state.phase==="voting") renderVoting(screen,sp); else if(state.phase==="ended") renderEnd(screen)}
function refreshVisibleTimers(){if(state.phase==="lobby"&&state.lobbyEndsAt){state.lobbyCountdown=secondsLeftFromEnd(state.lobbyEndsAt)}if(state.phase==="roleReveal"&&state.revealEndsAt){state.revealCountdown=secondsLeftFromEnd(state.revealEndsAt)}if(["night","day","voting"].includes(state.phase)&&state.phaseEndsAt){state.phaseSecondsLeft=secondsLeftFromEnd(state.phaseEndsAt)}render()}
function openJoinModal(){document.getElementById("joinModal").classList.add("show");document.getElementById("joinNameInput").focus()}function closeJoinModal(){document.getElementById("joinModal").classList.remove("show")}function openSettingsModal(){document.getElementById("settingsModal").classList.add("show")}function closeSettingsModal(){document.getElementById("settingsModal").classList.remove("show");render()}
bindPress(document.getElementById("nextPlayerBtn"),()=>selectNextPlayer());bindPress(document.getElementById("skipPhaseBtn"),()=>skipCurrentPhase());bindPress(document.getElementById("resetBtn"),()=>resetGame());bindPress(document.getElementById("settingsBtn"),()=>openSettingsModal());bindPress(document.getElementById("joinAddBtn"),()=>addPlayer());
document.getElementById("joinModal").addEventListener("click",(e)=>{if(e.target.id==="joinModal")closeJoinModal()});document.getElementById("settingsModal").addEventListener("click",(e)=>{if(e.target.id==="settingsModal")closeSettingsModal()});document.getElementById("joinNameInput").addEventListener("keydown",(e)=>{if(e.key==="Enter")addPlayer()});document.addEventListener("visibilitychange",()=>{if(!document.hidden){refreshVisibleTimers()}});
